@* Manages wizard step navigation and holds the Order state. *@

@if (currentStep == Step.Shipping)
{
    <ShippingStep Shipping="order.Shipping"
                  OnNext="HandleShippingComplete" />
}
else
{
    <PaymentStep Payment="order.Payment"
                 OnBack="HandleBack"
                 OnPlaceOrder="HandlePlaceOrder" />
}

@code {
    [Parameter, EditorRequired]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private enum Step { Shipping, Payment }

    private Step currentStep = Step.Shipping;
    private Order order = new();

    private void HandleShippingComplete(ShippingInfo shipping)
    {
        order.Shipping = shipping;
        currentStep = Step.Payment;
    }

    private void HandleBack()
    {
        currentStep = Step.Shipping;
    }

    private async Task HandlePlaceOrder(PaymentInfo payment)
    {
        order.Payment = payment;
        await OnOrderPlaced.InvokeAsync(order);
    }
}

@implements IAsyncDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@isValidating">
    <div>
        <label>Name</label>
        <input @bind="shipping.Name" />
    </div>
    <div>
        <label>Address</label>
        <input @bind="shipping.Address" />
    </div>
    <div>
        <label>City</label>
        <input @bind="shipping.City" />
    </div>
    <div>
        <label>Zip Code</label>
        <input @bind="shipping.ZipCode" />
    </div>
</fieldset>

@if (validationError is not null)
{
    <p class="validation-error">@validationError</p>
}

<button disabled="@isValidating" @onclick="HandleNext">
    @if (isValidating)
    {
        <span>ValidatingŌĆ”</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<ShippingInfo> OnNext { get; set; }

    private ShippingInfo shipping = new();
    private CancellationTokenSource? cts;
    private bool isValidating;
    private string? validationError;

    protected override void OnParametersSet()
    {
        // Copy parameter to private field ŌĆö never mutate [Parameter] directly.
        shipping = new ShippingInfo
        {
            Name = Shipping.Name,
            Address = Shipping.Address,
            City = Shipping.City,
            ZipCode = Shipping.ZipCode
        };
    }

    private async Task HandleNext()
    {
        validationError = null;

        // Cancel any previous in-flight validation.
        cts?.Cancel();
        cts?.Dispose();
        cts = new CancellationTokenSource();
        var token = cts.Token;

        isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                shipping.Address, shipping.City, shipping.ZipCode, token);

            if (!isValid)
            {
                validationError = "The address could not be verified.";
                return;
            }

            await OnNext.InvokeAsync(shipping);
        }
        catch (OperationCanceledException)
        {
            // Previous validation cancelled ŌĆö expected, nothing to do.
        }
        finally
        {
            isValidating = false;
        }
    }

    public ValueTask DisposeAsync()
    {
        cts?.Cancel();
        cts?.Dispose();
        return ValueTask.CompletedTask;
    }
}

